490→    /// Integration test: full auto-mock pipeline for a function with mixed dependencies.
491→    /// Validates that dependencies are classified, mocks are generated with correct
492→    /// return values, pure utilities are skipped, and user overrides are applied.
493→    #[test]
494→    fn auto_mock_pipeline_mixed_dependencies() {
495→        // Simulate a function that depends on fs.readFileSync, axios.get,
496→        // pg.query, lodash.map, and a custom library.
497→        let deps = vec![
498→            make_dep("readFileSync", "fs", TypeInfo::Str),
499→            make_dep("get", "axios", TypeInfo::Unknown),
500→            make_dep("query", "pg", TypeInfo::Unknown),
501→            make_dep("map", "lodash", TypeInfo::Unknown),
502→            make_dep("compute", "my-analytics-lib", TypeInfo::Int),
503→        ];
504→
505→        // User override: custom return value for the database query mock
506→        let mut overrides = HashMap::new();
507→        overrides.insert(
508→            "query".to_string(),
509→            MockOverride {
510→                return_values: Some(vec![json!({"rows": [{"id": 1, "name": "alice"}]})]),
511→                behavior: None,
512→            },
513→        );
514→
515→        let mocks = generate_auto_mocks(&deps, None, &overrides, &[]);
516→
517→        // 4 mocks generated: fs, network, db (overridden), and external other.
518→        // lodash (pure utility) is skipped.
519→        assert_eq!(mocks.len(), 4, "expected 4 mocks (lodash skipped)");
520→
521→        let by_symbol: HashMap<&str, &MockConfig> =
522→            mocks.iter().map(|m| (m.symbol.as_str(), m)).collect();
523→
524→        // fs.readFileSync → filesystem category, returns ""
525→        let fs_mock = by_symbol["readFileSync"];
526→        assert_eq!(fs_mock.return_values, vec![json!("")]);
527→        assert!(fs_mock.should_track_calls);
528→        assert_eq!(fs_mock.default_behavior, MockBehavior::RepeatLast);
529→
530→        // axios.get → network category, returns {status: 200, data: {}}
531→        let net_mock = by_symbol["get"];
532→        assert_eq!(net_mock.return_values, vec![json!({"status": 200, "data": {}})]);
533→        assert!(net_mock.should_track_calls);
534→
535→        // pg.query → database category, but overridden with custom rows
536→        let db_mock = by_symbol["query"];
537→        assert_eq!(
538→            db_mock.return_values,
539→            vec![json!({"rows": [{"id": 1, "name": "alice"}]})]
540→        );
541→        assert!(db_mock.should_track_calls);
542→
543→        // my-analytics-lib.compute → external other, type-aware default for Int
544→        let ext_mock = by_symbol["compute"];
545→        assert_eq!(ext_mock.return_values, vec![json!(0)]);
546→        assert!(ext_mock.should_track_calls);
547→
548→        // Verify lodash.map is NOT in the mock list
549→        assert!(!by_symbol.contains_key("map"));
550→    }
