 641→function extractDependencies(
 642→  body: ts.Block,
 643→  checker: ts.TypeChecker,
 644→  sourceFile: ts.SourceFile,
 645→  paramNames: Set<string>,
 646→): ExternalDependency[] {
 647→  const accumulators = new Map<string, DependencyAccumulator>();
 648→
 649→  walkForDependencies(body, checker, sourceFile, paramNames, accumulators);
 650→
 651→  return Array.from(accumulators.values()).map((acc) => ({
 652→    kind: acc.kind,
 653→    symbol: acc.symbol,
 654→    source_module: acc.sourceModule,
 655→    return_type: acc.returnType,
 656→    param_types: acc.paramTypes,
 657→    call_sites: acc.callSites,
 658→  }));
 659→}
