 770→// ---------------------------------------------------------------------------
 771→// Opaque type recognition (Node.js runtime resource types)
 772→// ---------------------------------------------------------------------------
 773→
 774→/** Known Node.js module → opaque type names. */
 775→const OPAQUE_NODE_TYPES: ReadonlyMap<string, ReadonlySet<string>> = new Map([
 776→  ["net", new Set(["Socket", "Server"])],
 777→  ["http", new Set(["IncomingMessage", "ServerResponse", "Server"])],
 778→  ["stream", new Set(["Readable", "Writable", "Transform", "Duplex", "PassThrough"])],
 779→  ["child_process", new Set(["ChildProcess"])],
 780→  ["worker_threads", new Set(["Worker"])],
 781→  ["fs", new Set(["ReadStream", "WriteStream"])],
 782→  ["tls", new Set(["TLSSocket", "Server"])],
 783→  ["dgram", new Set(["Socket"])],
 784→]);
 785→
 786→/** Reverse lookup: type name → list of modules that define it. */
 787→const OPAQUE_NAME_TO_MODULES: ReadonlyMap<string, readonly string[]> = (() => {
 788→  const map = new Map<string, string[]>();
 789→  for (const [mod, names] of OPAQUE_NODE_TYPES) {
 790→    for (const name of names) {
 791→      const existing = map.get(name);
 792→      if (existing) {
 793→        existing.push(mod);
 794→      } else {
 795→        map.set(name, [mod]);
 796→      }
 797→    }
 798→  }
 799→  return map;
 800→})();
