 810→  const name = symbol.getName();
 811→  const candidateModules = OPAQUE_NAME_TO_MODULES.get(name);
 812→  if (!candidateModules) return null;
 813→
 814→  // Verify the declaration comes from @types/node
 815→  const declarations = symbol.getDeclarations();
 816→  if (!declarations || declarations.length === 0) return null;
 817→
 818→  for (const decl of declarations) {
 819→    const fileName = decl.getSourceFile().fileName;
 820→    if (!fileName.includes("@types/node")) continue;
 821→
 822→    // Determine the module from the file path
 823→    for (const mod of candidateModules) {
 824→      const modulePattern = `/${mod.replace("_", "_")}`;
 825→      if (fileName.includes(modulePattern) || fileName.includes(`/${mod}.d.ts`)) {
 826→        return `${mod}.${name}`;
 827→      }
 828→    }
 829→
 830→    // Fallback: if it's from @types/node but we can't determine the exact module,
 831→    // use the first candidate module
 832→    return `${candidateModules[0]}.${name}`;
 833→  }
