 873→// Object type conversion
 874→// ---------------------------------------------------------------------------
 875→
 876→function convertObjectType(type: ts.ObjectType, checker: ts.TypeChecker): TypeInfo {
 877→  // Skip callable signatures (function types)
 878→  const callSignatures = type.getCallSignatures();
 879→  if (callSignatures.length > 0) {
 880→    return { kind: "unknown" };
 881→  }
 882→
 883→  const properties = type.getProperties();
 884→  if (properties.length === 0) {
 885→    return { kind: "object", fields: [] };
 886→  }
 887→
 888→  const fields: [string, TypeInfo][] = properties.map((prop) => {
 889→    const propType = checker.getTypeOfSymbol(prop);
 890→    const converted = convertType(propType, checker);
 891→
 892→    // Check if the property is optional
 893→    const isOptional = (prop.flags & ts.SymbolFlags.Optional) !== 0;
 894→    const fieldType = isOptional && converted.kind !== "nullable"
 895→      ? { kind: "nullable" as const, inner: converted }
 896→      : converted;
 897→
 898→    return [prop.name, fieldType];
 899→  });
 900→
 901→  return { kind: "object", fields };
 902→}
