 908→/**
 909→ * Convert a TypeScript AST expression into a SymExpr matching the protocol
 910→ * format. Expressions referencing function parameters produce symbolic nodes;
 911→ * everything else falls back to Unknown.
 912→ */
 913→function buildSymExpr(
 914→  expr: ts.Expression,
 915→  paramNames: Set<string>,
 916→): SymExpr {
 917→  if (ts.isParenthesizedExpression(expr)) {
 918→    return buildSymExpr(expr.expression, paramNames);
 919→  }
 920→
 921→  if (ts.isIdentifier(expr)) {
 922→    if (paramNames.has(expr.text)) {
 923→      return { kind: "param", name: expr.text, path: [] };
 924→    }
 925→    return { kind: "unknown" };
 926→  }
 927→
 928→  if (ts.isPropertyAccessExpression(expr)) {
 929→    const chain = resolveParamPropertyChain(expr, paramNames);
 930→    if (chain) {
 931→      return { kind: "param", name: chain.name, path: chain.path };
 932→    }
 933→    return { kind: "unknown" };
 934→  }
 935→
 936→  if (ts.isNumericLiteral(expr)) {
 937→    const n = Number(expr.text);
 938→    if (Number.isInteger(n)) {
 939→      return { kind: "const", type: "int", value: n };
 940→    }
 941→    return { kind: "const", type: "float", value: n };
 942→  }
 943→
 944→  if (ts.isStringLiteral(expr)) {
 945→    return { kind: "const", type: "str", value: expr.text };
 946→  }
 947→
 948→  if (expr.kind === ts.SyntaxKind.TrueKeyword) {
 949→    return { kind: "const", type: "bool", value: true };
 950→  }
 951→
 952→  if (expr.kind === ts.SyntaxKind.FalseKeyword) {
 953→    return { kind: "const", type: "bool", value: false };
 954→  }
 955→
 956→  if (expr.kind === ts.SyntaxKind.NullKeyword) {
 957→    return { kind: "const", type: "null" };
 958→  }
 959→
 960→  if (ts.isBinaryExpression(expr)) {
 961→    const op = mapBinaryOp(expr.operatorToken.kind);
 962→    if (op) {
 963→      const left = buildSymExpr(expr.left, paramNames);
 964→      const right = buildSymExpr(expr.right, paramNames);
 965→      return { kind: "bin_op", op, left, right };
 966→    }
 967→    return { kind: "unknown" };
 968→  }
 969→
 970→  if (ts.isPrefixUnaryExpression(expr)) {
 971→    const op = mapUnaryOp(expr.operator);
 972→    if (op) {
 973→      const operand = buildSymExpr(expr.operand, paramNames);
 974→      return { kind: "un_op", op, operand };
 975→    }
 976→    return { kind: "unknown" };
 977→  }
 978→
 979→  if (ts.isTypeOfExpression(expr)) {
 980→    const operand = buildSymExpr(expr.expression, paramNames);
 981→    return { kind: "un_op", op: "typeof" as UnOpKind, operand };
 982→  }
 983→
 984→  if (ts.isCallExpression(expr)) {
 985→    if (ts.isPropertyAccessExpression(expr.expression)) {
 986→      const methodName = expr.expression.name.text;
 987→      const receiver = buildSymExpr(expr.expression.expression, paramNames);
 988→      const args = expr.arguments.map((a) => buildSymExpr(a, paramNames));
 989→      return { kind: "call", name: methodName, receiver, args };
 990→    }
 991→    if (ts.isIdentifier(expr.expression)) {
 992→      const args = expr.arguments.map((a) => buildSymExpr(a, paramNames));
 993→      return { kind: "call", name: expr.expression.text, receiver: null, args };
 994→    }
 995→    return { kind: "unknown" };
 996→  }
 997→
 998→  return { kind: "unknown" };
 999→}
