  1→// Example 12: External dependencies and auto-mocking
  2→// Tests shatter's automatic mock generation for functions that depend on
  3→// external modules: filesystem I/O, network calls, database queries, and
  4→// pure utility libraries.
  5→//
  6→// Shatter classifies each dependency and generates appropriate mocks:
  7→//   - fs/path        → filesystem I/O stubs (returns "", null, etc.)
  8→//   - axios/fetch    → network stubs (returns {status: 200, data: {}})
  9→//   - pg/prisma      → database stubs (returns {rows: []})
 10→//   - lodash/dayjs   → pure utility passthrough (no mock needed)
 11→
 12→import * as fs from "fs";
 13→import * as path from "path";
 14→
 15→// ── Filesystem dependency ──────────────────────────────────────────────
 16→//
 17→// EXPECTED BRANCHES (4):
 18→//   1. configPath is empty          → throws Error("empty config path")
 19→//   2. file does not exist          → returns "missing"
 20→//   3. file content is empty        → returns "empty"
 21→//   4. file has content             → returns parsed content length
 22→//
 23→// MOCKS: fs.existsSync → true/false, fs.readFileSync → string
 24→//
 25→// DIFFICULTY: Easy. Two string branches plus mock return values.
 26→export function loadConfig(configPath: string): string {
 27→    if (configPath.length === 0) {
 28→        throw new Error("empty config path");
 29→    }
 30→
 31→    const fullPath = path.resolve(configPath);
 32→
 33→    if (!fs.existsSync(fullPath)) {
 34→        return "missing";
 35→    }
 36→
 37→    const content = fs.readFileSync(fullPath, "utf-8");
 38→    if (content.length === 0) {
 39→        return "empty";
 40→    }
 41→
 42→    return `loaded:${content.length}`;
 43→}
 44→
 45→// ── Network dependency (simulated via function signature) ──────────────
 46→//
 47→// This function takes a `fetchFn` parameter typed to simulate an HTTP client.
 48→// In real code this would be `axios.get` or `fetch`. Shatter should detect
 49→// the external dependency and generate a network-category mock.
 50→//
 51→// EXPECTED BRANCHES (4):
 52→//   1. url is empty                 → throws Error("empty url")
 53→//   2. response status >= 400       → returns "error:<status>"
 54→//   3. response has no data         → returns "no-data"
 55→//   4. response has data            → returns "ok:<key count>"
 56→//
 57→// DIFFICULTY: Easy. Numeric comparison on status plus null check on data.
 58→export function fetchAndProcess(
 59→    url: string,
 60→    response: { status: number; data: Record<string, unknown> | null }
 61→): string {
 62→    if (url.length === 0) {
 63→        throw new Error("empty url");
 64→    }
 65→
 66→    if (response.status >= 400) {
 67→        return `error:${response.status}`;
 68→    }
 69→
 70→    if (!response.data) {
 71→        return "no-data";
 72→    }
 73→
 74→    return `ok:${Object.keys(response.data).length}`;
 75→}
 76→
 77→// ── Database dependency (simulated via parameter) ──────────────────────
 78→//
 79→// EXPECTED BRANCHES (5):
 80→//   1. table is empty               → throws Error("empty table")
 81→//   2. table has invalid chars       → throws Error("invalid table name")
 82→//   3. rows is empty                → returns "no-rows"
 83→//   4. rows has one item            → returns "single:<value>"
 84→//   5. rows has multiple items      → returns "multiple:<count>"
 85→//
 86→// DIFFICULTY: Easy. String validation plus array length checks.
 87→export function queryTable(
 88→    table: string,
 89→    rows: Array<{ id: number; value: string }>
 90→): string {
 91→    if (table.length === 0) {
 92→        throw new Error("empty table");
 93→    }
 94→
 95→    if (!/^[a-zA-Z_]\w*$/.test(table)) {
 96→        throw new Error("invalid table name");
 97→    }
 98→
 99→    if (rows.length === 0) {
100→        return "no-rows";
101→    }
102→
103→    if (rows.length === 1) {
104→        return `single:${rows[0].value}`;
105→    }
106→
107→    return `multiple:${rows.length}`;
108→}
109→
110→// ── Pure utility usage ─────────────────────────────────────────────────
111→//
112→// Uses path.join (filesystem category) but the logic is pure string
113→// manipulation. Demonstrates that even when a function imports a utility
114→// module, Shatter can still explore it meaningfully.
115→//
116→// EXPECTED BRANCHES (3):
117→//   1. parts is empty               → returns ""
118→//   2. any part contains ".."       → throws Error("path traversal")
119→//   3. normal parts                 → returns joined path
120→//
121→// DIFFICULTY: Easy. Array emptiness check plus string search.
122→export function buildSafePath(parts: string[]): string {
123→    if (parts.length === 0) {
124→        return "";
125→    }
126→
127→    for (const part of parts) {
128→        if (part.includes("..")) {
129→            throw new Error("path traversal");
130→        }
131→    }
132→
133→    return path.join(...parts);
134→}
